import React, { useState, useEffect } from 'react';
import './header.css';
import { FaBars, FaTimes, FaPhoneAlt, FaEnvelope, FaStar, FaChevronDown, FaChevronRight } from 'react-icons/fa';
import { FaArrowRight } from "react-icons/fa";
import { Link } from 'gatsby';

const Header: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isTopBarVisible, setIsTopBarVisible] = useState(true);
  const [isScrolled, setIsScrolled] = useState(false);
  const [lastScrollY, setLastScrollY] = useState(0);
  const [isMobileServicesOpen, setIsMobileServicesOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
    if (!isMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  };

  const closeMenu = () => {
    setIsMenuOpen(false);
    document.body.style.overflow = 'unset';
  };

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;
      if (currentScrollY > 100) {
        setIsScrolled(true);
      } else {
        setIsScrolled(false);
      }

      if (currentScrollY > 80 && currentScrollY > lastScrollY) {
        setIsTopBarVisible(false);
      } else {
        setIsTopBarVisible(true);
      }
      setLastScrollY(currentScrollY);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, [lastScrollY]);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth > 768 && isMenuOpen) closeMenu();
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [isMenuOpen]);

  useEffect(() => {
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, []);

  const navLinks = [
    { name: 'Home', href: '/' },
    { 
      name: 'Services', 
      href: '/#services',
      submenu: [
        { name: 'Wood Fencing', href: '/wood-fencing' },
        { name: 'Vinyl Fencing', href: '/vinyl-fencing' },
        { name: 'Aluminum Fencing', href: '/aluminum-fencing' },
        { name: 'Chain‑Link Fencing', href: '/chain-link-fencing' },
        { name: 'Ornamental Iron', href: '/ornamental-iron-fencing' },
        { name: 'Composite Fencing', href: '/composite-fencing' },
        { name: 'Mixed Material', href: '/mixed-material-fencing' },
        { name: 'Gate Solutions', href: '/gate-solutions' },
      ]
    },
    { name: 'Gallery', href: '/#gallery' },
    { name: 'Reviews', href: '/#reviews' },
    { name: 'Contact', href: '/contact' },
  ];

  return (
    <header className={`header ${isScrolled ? 'header-scrolled' : ''}`}>
      {/* Top Bar - hides on scroll down */}
      <div className={`top-bar ${!isTopBarVisible ? 'top-bar-hidden' : ''}`}>
        <div className="container">
          <div className="top-bar-content">
            <div className="contact-info">
              <a href="tel:+17742360051" className="contact-link">
                <FaPhoneAlt className="icon" />
                <span>(774) 236-0051</span>
              </a>
              <span className="divider">|</span>
              <a href="mailto:Jskfencingcape@gmail.com" className="contact-link">
                <FaEnvelope className="icon" />
                <span>Jskfencingcape@gmail.com</span>
              </a>
            </div>
            <div className="rating-info">
              <a
                href="https://www.bbb.org/us/ma/centerville/profile/fence-contractors/jsk-fencing-llc-0021-556180"
                target="_blank"
                rel="noopener noreferrer"
                className="bbb-link"
              >
                <FaStar className="star-icon" />
                <span>BBB Accredited A+ Rating</span>
              </a>
            </div>
          </div>
        </div>
      </div>

      {/* Main Navigation */}
      <div className="main-nav">
        <div className="container">
          <div className="nav-wrapper">
            <div className="logo">
              <a href="/" className="logo-link">
                JSK <span className="logo-accent">Fencing</span>
              </a>
            </div>

            <nav className="desktop-nav">
              <ul className="nav-list">
                {navLinks.map((link) => (
                  <li key={link.name} className={link.submenu ? 'has-submenu' : ''}>
                    <a href={link.href} className="nav-link">
                      {link.name} {link.submenu && <FaChevronDown className="dropdown-icon" />}
                    </a>
                    {link.submenu && (
                      <div className="submenu">
                        <ul className="submenu-list">
                          {link.submenu.map((item) => (
                            <li key={item.name}>
                              <a href={item.href} className="submenu-link">
                                {item.name}
                              </a>
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}
                  </li>
                ))}
              </ul>
            </nav>

          <div className="cta-wrapper">
  <a href="tel:+17742360051" className="cta-button">
    <span className="cta-text">Get a Quote</span>
    <span className="cta-icon">
      <FaArrowRight />
    </span>
  </a>
</div>

            <button
              className="mobile-menu-button"
              onClick={toggleMenu}
              aria-label="Toggle menu"
              aria-expanded={isMenuOpen}
            >
              {isMenuOpen ? <FaTimes /> : <FaBars />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Slide‑in Menu */}
      <div className={`mobile-menu-overlay ${isMenuOpen ? 'mobile-menu-open' : ''}`}>
        <div className="mobile-menu-content">
          <div className="mobile-menu-header">
           
            <button className="mobile-close-button" onClick={closeMenu}>
              <FaTimes />
            </button>
          </div>
          <nav className="mobile-nav">
            <ul className="mobile-nav-list">
              {navLinks.map((link) => (
                <li key={link.name} className="mobile-nav-item">
                  <div className="mobile-nav-link-wrapper">
                    <a href={link.href} className="mobile-nav-link" onClick={!link.submenu ? closeMenu : undefined}>
                      {link.name}
                    </a>
                    {link.submenu && (
                      <button 
                        className={`submenu-toggle ${isMobileServicesOpen ? 'active' : ''}`}
                        onClick={() => setIsMobileServicesOpen(!isMobileServicesOpen)}
                      >
                        <FaChevronRight />
                      </button>
                    )}
                  </div>
                  
                  {link.submenu && (
                    <ul className={`mobile-submenu ${isMobileServicesOpen ? 'open' : ''}`}>
                      {link.submenu.map((item) => (
                        <li key={item.name}>
                          <a href={item.href} className="mobile-submenu-link" onClick={closeMenu}>
                            {item.name}
                          </a>
                        </li>
                      ))}
                    </ul>
                  )}
                </li>
              ))}
            </ul>
          </nav>
          <div className="mobile-cta-wrapper">
            <a href="tel:+17742360051" className="mobile-cta-button" onClick={closeMenu}>
              Get a Quote
            </a>
          </div>
          <div className="mobile-contact-info">
            <a href="tel:+17742360051" className="mobile-contact-link">
              <FaPhoneAlt /> (774) 236-0051
            </a>
            <a href="mailto:Jskfencingcape@gmail.com" className="mobile-contact-link">
              <FaEnvelope /> Jskfencingcape@gmail.com
            </a>
            <a
              href="https://www.bbb.org/us/ma/centerville/profile/fence-contractors/jsk-fencing-llc-0021-556180"
              target="_blank"
              rel="noopener noreferrer"
              className="mobile-bbb-link"
            >
              <FaStar /> BBB Accredited A+ Rating
            </a>
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;